#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = fract(vUv);
vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw * 1 + rand_frame.xy;
vec2 d = uTexSize.zw*12;
vec3 dx = (2*GetBlur3(vUvOriginal + vec2(1,0)*d) - 2*GetBlur3(vUvOriginal -vec2(1,0)*d))*0.5;
vec3 dy = (2*GetBlur3(vUvOriginal + vec2(0,1)*d) - 2*GetBlur3(vUvOriginal -vec2(0,1)*d))*0.5;

vec2 uvx = vUv
           + (texture(sampler_noise_lq, dither_uv).xy-0.5)*uTexSize.zw*0
           - vec2(dx.x,dy.x)*uTexSize.zw*0;
    ret.x = texture( sampler_fc_main, uvx ).x
          - (GetBlur3(uvx)-texture( sampler_fc_main, uvx )).x*0.1
          - 0.035;

vec2 uvy = vUvOriginal
           + (texture(sampler_noise_lq, dither_uv).xy-0.5)*uTexSize.zw*4
           - vec2(dx.x,dy.x)*uTexSize.zw*4
           + vec2(dx.y,dy.y)*uTexSize.zw*8;

ret.y = tex2d(sampler_fc_main,uvy).y
      + (texture(sampler_noise_lq, dither_uv).xyz-0.5)*0.1
      - 0.012
      + (tex2d(sampler_pc_main,vUvOriginal).z)*0.2;


vec2 uvz = vUvOriginal
           + (texture(sampler_noise_lq, dither_uv).xy-0.5)*uTexSize.zw*2
           + vec2(dy.x,-dx.x)*uTexSize.zw*64
           + vec2(dx.z,dy.z)*uTexSize.zw*0;
ret.z = tex2d(sampler_fc_main,uvz).z
      + (tex2d(sampler_fc_main,uvz).z-GetBlur2(uvz).z)*0.2
      + (texture(sampler_noise_lq, dither_uv).xyz)*0.1
      - GetBlur3(vUvOriginal).x
      - clamp01(1-GetBlur2(vUvOriginal).x)*0.04;

  fragColor = ret;
}

